fn set_field(state: &mut LuaState, key: &[u8], value: i32, delta: i32) -> Result<(), LuaError> {
    // C: lua_pushinteger(L, (lua_Integer)value + delta);
    state.push(LuaValue::Int((value as i64) + (delta as i64)));
