    set_field(state, b"day",   stm.tm_mday, 0)?;
    // C: setfield(L, "hour",  stm->tm_hour, 0);
    set_field(state, b"hour",  stm.tm_hour, 0)?;
    // C: setfield(L, "min",   stm->tm_min,  0);
    set_field(state, b"min",   stm.tm_min,  0)?;
